// TOPIC
const TOPIC_AUDIT = "Henkelv2/Shanghai/Logistics/Exceptions/State/Audit_Log";

let incomingTopic = msg.topic;
let payload = msg.payload;

// 1. Get Audit DB
let auditDB = global.get('audit_log_db') || { items: [] };

// 2. Parse Topic Smartly
// Format: Henkelv2/Shanghai/Logistics/[MODULE]/[SUBMODULE?]/Action/[ACTION_NAME]
let parts = incomingTopic.split('/');

// Only log "Action" topics (ignore State updates to prevent loops)
if (!incomingTopic.includes("/Action/")) return null;

// Extract Action Name (Always the last part)
let actionName = parts[parts.length - 1];

// Extract Module (Always 4th part: Henkelv2=0, Shanghai=1, Logistics=2, MODULE=3)
let moduleName = parts[3];

// Optional: Add Submodule if it exists (e.g. "Internal/Quality")
if (parts[4] !== "Action" && parts[4] !== "State") {
    moduleName += " / " + parts[4];
}

// 3. Create Log Entry
let logEntry = {
    log_id: "LOG-" + Date.now(),
    timestamp: Date.now(),
    user: payload.operator || payload.operator_id || payload.user || "User_Admin",
    action: actionName,
    module: moduleName,
    details: payload,
    status: "SUCCESS"
};

// 4. Add to List (Limit to 50)
auditDB.items.unshift(logEntry);
if (auditDB.items.length > 50) auditDB.items.pop();

// 5. Save & Publish
global.set('audit_log_db', auditDB);

msg.topic = TOPIC_AUDIT;
msg.payload = {
    version: "1.0",
    topics: [{ path: TOPIC_AUDIT, type: "state", value: auditDB }]
};

return msg;

// TOPIC
const TOPIC_TRACE_RESULT = "Henkelv2/Shanghai/Logistics/Internal/Quality/State/Trace_Result";

let query = msg.payload.query; // Expected: Batch ID (e.g., "B-21337")

// 1. Get ALL Data Sources
let inventory = global.get('internal_stock_list') || [];
let qcQueue = global.get('qc_queue') || { items: [] };
let reservations = global.get('reservation_db') || { items: [] };
let tasks = global.get('picking_task_db') || { items: [] };
let audit = global.get('audit_log_db') || { items: [] };

// 2. Initialize Timeline
let timeline = [];

// --- EVENT A: ARRIVAL (Inferred from Audit or Inventory creation) ---
// We'll search Audit log for "Add to Inspection Queue" or similar for this ID
let creationLog = audit.items.find(l => l.details && l.details.batch_id === query);
if (creationLog) {
    timeline.push({
        stage: "Inbound",
        event: "Goods Receipt",
        time: creationLog.timestamp,
        details: "Received at Dock",
        status: "success"
    });
} else {
    // Fallback if audit is empty (demo start)
    timeline.push({
        stage: "Inbound",
        event: "Goods Receipt (Legacy)",
        time: Date.now() - 10000000,
        details: "Imported Data",
        status: "success"
    });
}

// --- EVENT B: QUALITY CONTROL ---
// Search Audit for "Submit_Result" with this Batch ID
let qcLog = audit.items.find(l => l.action === "Submit_Result" && l.details.batch_id === query);
if (qcLog) {
    timeline.push({
        stage: "Quality",
        event: "QC Inspection",
        time: qcLog.timestamp,
        details: "Result: " + qcLog.details.result,
        status: qcLog.details.result === "PASS" ? "success" : "error"
    });
}

// --- EVENT C: ALLOCATION ---
// Search Reservations for this Batch ID in 'allocated_to' logic? 
// Actually, we check Audit for "Run_Allocation"
// This is tricky because Allocation audit logs the Res ID, not always the Batch ID directly in the main payload.
// We can check if the Batch is currently allocated in Inventory.
let invItem = inventory.find(i => i.batch_id === query);
if (invItem && invItem.status === "ALLOCATED") {
    timeline.push({
        stage: "Planning",
        event: "Allocated to Order",
        time: Date.now(), // Real timestamp hard to get without better audit linkage, using 'Now' for demo
        details: "Locked for Production",
        status: "warning"
    });
}

// --- EVENT D: PICKING ---
let pickTask = tasks.items.find(t => t.batch_id === query);
if (pickTask) {
    timeline.push({
        stage: "Execution",
        event: "Picking Task Generated",
        time: pickTask.created_at,
        details: "Move to " + pickTask.to_loc,
        status: "success"
    });
    if (pickTask.status === "COMPLETED") {
        timeline.push({
            stage: "Execution",
            event: "Picking Confirmed",
            time: pickTask.completed_at,
            details: "Arrived at Line Side",
            status: "success"
        });
    }
}

// --- EVENT E: CONSUMPTION ---
// Search Audit for "Consume_Material"
let consumeLog = audit.items.find(l => l.action === "Consume_Material" && l.details.batch_id === query);
if (consumeLog) {
    timeline.push({
        stage: "Production",
        event: "Consumed in Production",
        time: consumeLog.timestamp,
        details: "Qty: " + consumeLog.details.qty_to_consume,
        status: "success"
    });
}

// Sort Timeline
timeline.sort((a,b) => a.time - b.time);

// 3. Publish Result
msg.topic = TOPIC_TRACE_RESULT;
msg.payload = {
    version: "1.0",
    topics: [{ path: TOPIC_TRACE_RESULT, type: "state", value: { batch_id: query, timeline: timeline } }]
};
return msg;

// TOPIC
const TOPIC_QUEUE = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Task_Queue";

// 1. Get existing queue
let taskQueue = global.get('internal_task_queue') || { queue: [], last_updated: 0 };

// 2. GET MASTER DATA
let masterMaterials = global.get('master_materials') || [];
let masterLocations = global.get('master_locations') || [];

// Fallbacks
if (masterMaterials.length === 0) masterMaterials = [{ code: 'RES-001', desc: 'Fallback Resin', hazard: 'None' }];
if (masterLocations.length === 0) masterLocations = [{ code: 'ZONE-A-01', zone: 'A' }];

// --- LOGIC CHANGE: PRIORITIZE NEWEST ---
// Pick newest material (Index 0)
let mat = masterMaterials.length > 0 ? masterMaterials[0] : masterMaterials[0];
// Pick newest location (Index 0) - This ensures your new "LOC-TEST-01" is chosen
let loc = masterLocations.length > 0 ? masterLocations[0] : masterLocations[0];

let uniqueId = Math.floor(Math.random() * 100000);
let newTask = {
    id: 'TSK-' + uniqueId,
    hu: 'HU-2026-' + uniqueId,
    material: mat.code,
    desc: mat.desc,
    batch: 'B2026-' + (Math.floor(Math.random() * 900) + 100),
    qty: (Math.floor(Math.random() * 20) * 50 + 50) + ' ' + (mat.uom || 'KG'),
    status: 'QUARANTINE',
    type: 'PUTAWAY',
    source: 'DOCK-IN-01',
    hazmat: mat.hazard && mat.hazard !== 'None',
    temp: mat.storage || 'Ambient',
    aging: 'Just Now',
    strategy: mat.storage === 'Cold' ? 'COLD_CHAIN' : 'FIFO',
    suggestionStatus: 'SUGGESTED',
    // THIS IS THE KEY: The system suggests your new bin
    topBin: loc.code
};

// 4. Add to Queue
taskQueue.queue.push(newTask);
taskQueue.last_updated = Date.now();

// 5. Save & Publish
global.set('internal_task_queue', taskQueue);

msg.payload = {
    version: "1.0",
    topics: [{ path: TOPIC_QUEUE, type: "state", value: taskQueue }]
};
msg.topic = TOPIC_QUEUE;
return msg;

// TOPICS
const TOPIC_QUEUE = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Task_Queue";
const TOPIC_INVENTORY = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Inventory_Level";

let action = msg.payload;
// Expected: { task_id, hu, target_bin, operator ... }

// 1. Get DBs
let taskQueue = global.get('internal_task_queue') || { queue: [] };
let inventory = global.get('internal_stock_list') || [];

// 2. REMOVE FROM TASK QUEUE (ROBUST MATCHING)
// We try to find the task by ID first, then by HU.
let taskIndex = taskQueue.queue.findIndex(t =>
    (t.id && t.id === action.task_id) ||
    (t.hu && t.hu === action.hu)
);

let completedTask = null;

if (taskIndex !== -1) {
    // Found it! Capture the data before deleting
    completedTask = taskQueue.queue[taskIndex];
    // Remove from the queue
    taskQueue.queue.splice(taskIndex, 1);
} else {
    // Debugging: If we can't find it, log why
    node.warn("Could not find task to delete. Action: " + JSON.stringify(action));
}

// 3. UPDATE INVENTORY LOCATION
// (Physical object moves to new bin)
let itemIndex = inventory.findIndex(i => i.batch_id === action.hu || i.hu === action.hu);

if (itemIndex !== -1) {
    // Update existing stock record
    inventory[itemIndex].location = action.target_bin;
    inventory[itemIndex].last_moved = Date.now();
} else if (completedTask) {
    // If not in inventory DB yet (demo mode), create it from the task data
    inventory.unshift({
        hu: completedTask.hu || action.hu,
        sku: completedTask.material,
        desc: completedTask.desc,
        qty: completedTask.qty,
        status: completedTask.status || "QUARANTINE",
        location: action.target_bin,
        batch_id: completedTask.batch || action.hu
    });
}

// 4. Save Globals
taskQueue.last_updated = Date.now();
global.set('internal_task_queue', taskQueue);
global.set('internal_stock_list', inventory);

// 5. Prepare Outputs
let msgQueue = {
    topic: TOPIC_QUEUE,
    payload: { version: "1.0", topics: [{ path: TOPIC_QUEUE, type: "state", value: taskQueue }] }
};

let msgInv = {
    topic: TOPIC_INVENTORY,
    payload: {
        version: "1.0",
        topics: [{ path: TOPIC_INVENTORY, type: "state", value: { last_updated: Date.now(), stock_items: inventory } }]
    }
};

// Return: [Update Queue, Update Inventory, Log to Debug]
return [msgQueue, msgInv, { payload: "Executed Putaway for " + action.hu }];

// TOPICS
const TOPIC_QUEUE = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Task_Queue";
const TOPIC_INVENTORY = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Inventory_Level";
const TOPIC_EX = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Exceptions";

let receipt = msg.payload;
// Expected: { doc_id, dock, lines: [...], outcome, operator }

// 1. Get Global DBs
let taskQueue = global.get('internal_task_queue') || { queue: [], last_updated: 0 };
let inventory = global.get('internal_stock_list') || [];
let exDB = global.get('exception_db') || { items: [] };

// 2. Process Lines
if (receipt.lines && receipt.lines.length > 0) {
    receipt.lines.forEach(line => {

        let uniqueId = Math.floor(Math.random() * 100000);
        let huId = line.containerId || ('HU-NEW-' + uniqueId);
        let batchId = line.batch || ("BATCH-" + uniqueId);

        // Determine Status
        let status = (receipt.outcome === 'REJECT') ? "BLOCKED" : "QUARANTINE";
        let target = (receipt.outcome === 'REJECT') ? "REJECT-CAGE" : "ZONE-Q-01-A";

        // --- NEW: AUTO-CREATE EXCEPTION IF BLOCKED ---
        if (status === "BLOCKED") {
            let newEx = {
                id: "EX-" + Math.floor(Math.random() * 10000),
                type: "RECEIPT_REJECTION",
                severity: "CRITICAL",
                source_ref: huId,
                reported_by: receipt.operator || "System",
                timestamp: new Date().toISOString(),
                status: "OPEN",
                details: "Delivery Refused at Dock " + receipt.dock
            };
            exDB.items.unshift(newEx);
        }

        // --- A. CREATE PUTAWAY TASK ---
        // Check duplicate task
        let taskExists = taskQueue.queue.find(t => t.hu === huId);
        if (!taskExists) {
            taskQueue.queue.unshift({
                id: 'TSK-' + uniqueId,
                hu: huId,
                material: line.code || "UNKNOWN",
                desc: line.desc || "Received Material",
                batch: batchId,
                qty: (line.qty || 0) + " " + (line.uom || "KG"),
                status: status,
                type: 'PUTAWAY', // Added for Unified Inbound Filter
                source: receipt.dock || "DOCK-IN-01",
                hazmat: true,
                temp: 'Ambient',
                aging: 'Just Now',
                strategy: 'HAZMAT_ISO',
                suggestionStatus: 'SUGGESTED',
                topBin: target,
                created_at: Date.now()
            });
        }

        // --- B. CREATE INVENTORY RECORD ---
        let stockExists = inventory.find(i => i.hu === huId);
        if (!stockExists) {
            inventory.unshift({
                hu: huId,
                batch_id: batchId,
                sku: line.code,
                desc: line.desc,
                qty: line.qty,
                uom: line.uom || "KG",
                status: status, // Will be BLOCKED or QUARANTINE
                location: receipt.dock || "DOCK-IN-01",
                warehouse: "Shanghai Internal",
                last_updated: Date.now()
            });
        }
    });
}

// 3. Save Globals
global.set('internal_task_queue', taskQueue);
global.set('internal_stock_list', inventory);
global.set('exception_db', exDB);

// 4. Prepare Outputs
let msgQueue = {
    topic: TOPIC_QUEUE,
    payload: { version: "1.0", topics: [{ path: TOPIC_QUEUE, type: "state", value: taskQueue }] }
};

let msgInv = {
    topic: TOPIC_INVENTORY,
    payload: {
        version: "1.0",
        topics: [{ path: TOPIC_INVENTORY, type: "state", value: { last_updated: Date.now(), stock_items: inventory } }]
    }
};

let msgEx = {
    topic: TOPIC_EX,
    payload: { version: "1.0", topics: [{ path: TOPIC_EX, type: "state", value: exDB }] }
};

// Return: [Task_Update, Inventory_Update, Exception_Update]
// You MUST add a 3rd output to the Function node for this to work!
return [msgQueue, msgInv, msgEx];

// TOPIC
const TOPIC_QC_QUEUE = "Henkelv2/Shanghai/Logistics/Internal/Quality/State/Inspection_Queue";

let receipt = msg.payload;
// Expected: { doc_id, lines: [...], outcome ... }

// 1. Get QC Queue
let qcQueue = global.get('qc_queue') || { items: [] };

// 2. Filter for items that NEED QC
// (In a real app, we check Master Data. Here, we assume ALL raw materials need QC)
if (receipt.outcome === 'ACCEPT_QUARANTINE' && receipt.lines) {
    receipt.lines.forEach(line => {

        // Check duplicate
        let exists = qcQueue.items.find(i => i.batch_id === line.batch);
        if (exists) return;

        // Create QC Task
        let qcTask = {
            sample_id: "SMP-" + Math.floor(Math.random() * 100000),
            batch_id: line.batch || "BATCH-UNK",
            sku: line.code,
            desc: line.desc,
            supplier: receipt.supplier || "Unknown",
            qty: line.qty,
            arrival_time: Date.now(),
            status: "PENDING_SAMPLING",
            required_tests: ["Viscosity", "pH Level", "Purity", "Visual Check"],
            location: receipt.dock // Where the sampler can find it initially
        };

        // Add to Queue
        qcQueue.items.unshift(qcTask);
    });
}

// 3. Save & Publish
global.set('qc_queue', qcQueue);

msg.payload = {
    version: "1.0",
    topics: [{ path: TOPIC_QC_QUEUE, type: "state", value: qcQueue }]
};
msg.topic = TOPIC_QC_QUEUE;

return [msg, { payload: "Generated QC Tasks" }];

// TOPICS
const TOPIC_QC_QUEUE = "Henkelv2/Shanghai/Logistics/Internal/Quality/State/Inspection_Queue";
const TOPIC_DECISION_QUEUE = "Henkelv2/Shanghai/Logistics/Internal/Quality/State/Decision_Queue";

let action = msg.payload;
// Expected: { batch_id, result: "PASS"|"FAIL", lab_data: {...}, technician: "..." }

// 1. Get Queues
let qcQueue = global.get('qc_queue') || { items: [] };
let decisionQueue = global.get('decision_queue') || { items: [] };

// 2. Find and Remove from QC Queue (Lab work is done)
let itemIndex = qcQueue.items.findIndex(i => i.batch_id === action.batch_id);
if (itemIndex === -1) {
    node.warn("Item not found in QC Queue: " + action.batch_id);
    return null;
}

let item = qcQueue.items[itemIndex];
qcQueue.items.splice(itemIndex, 1);

// 3. Enrich Item with Lab Data
item.lab_result = action.result; // "PASS" or "FAIL"
item.lab_data = action.lab_data;
item.tested_by = action.technician;
item.tested_at = Date.now();
item.status = "PENDING_APPROVAL"; // Moves to Manager Review

// 4. Add to Decision Queue
decisionQueue.items.unshift(item);

// 5. Save Globals
global.set('qc_queue', qcQueue);
global.set('decision_queue', decisionQueue);

// 6. Publish Updates
let msgQC = {
    topic: TOPIC_QC_QUEUE,
    payload: { version: "1.0", topics: [{ path: TOPIC_QC_QUEUE, type: "state", value: qcQueue }] }
};

let msgDecision = {
    topic: TOPIC_DECISION_QUEUE,
    payload: { version: "1.0", topics: [{ path: TOPIC_DECISION_QUEUE, type: "state", value: decisionQueue }] }
};

return [msgQC, msgDecision];

// TOPICS
const TOPIC_DECISION_QUEUE = "Henkelv2/Shanghai/Logistics/Internal/Quality/State/Decision_Queue";
const TOPIC_INVENTORY = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Inventory_Level";

let action = msg.payload;
// Expected: { batch_id, action: "RELEASE"|"BLOCK"|"REWORK", reason: "...", manager: "..." }

// 1. Get DBs
let decisionQueue = global.get('decision_queue') || { items: [] };
let inventory = global.get('internal_stock_list') || [];

// 2. Find and Remove from Decision Queue
let itemIndex = decisionQueue.items.findIndex(i => i.batch_id === action.batch_id);
if (itemIndex === -1) {
    node.warn("Item not found in Decision Queue: " + action.batch_id);
    return null;
}

let item = decisionQueue.items[itemIndex];
decisionQueue.items.splice(itemIndex, 1); // Remove from list

// 3. UPDATE PHYSICAL INVENTORY STATUS
let invIndex = inventory.findIndex(i => i.batch_id === action.batch_id);
let newStatus = "QUARANTINE"; // Default

if (invIndex !== -1) {
    // --- LOGIC: RELEASE ---
    if (action.action === "RELEASE") {
        inventory[invIndex].status = "AVAILABLE";
        inventory[invIndex].location = "ZONE-A-RAW"; // Simulate logic to move to picking zone (optional)
        inventory[invIndex].quality_data = item.lab_data;
        newStatus = "AVAILABLE";
    }
    // --- LOGIC: BLOCK ---
    else if (action.action === "BLOCK") {
        inventory[invIndex].status = "BLOCKED";
        inventory[invIndex].location = "REJECT-CAGE";
        newStatus = "BLOCKED";
    }
    // --- LOGIC: REWORK ---
    else if (action.action === "REWORK") {
        inventory[invIndex].status = "REWORK";
        // Ideally, this triggers a new production order, but for now we just label it.
        newStatus = "REWORK";
    }
}

// 4. Save Globals
global.set('decision_queue', decisionQueue);
global.set('internal_stock_list', inventory);

// 5. Publish
let msgDecision = {
    topic: TOPIC_DECISION_QUEUE,
    payload: { version: "1.0", topics: [{ path: TOPIC_DECISION_QUEUE, type: "state", value: decisionQueue }] }
};

let msgInv = {
    topic: TOPIC_INVENTORY,
    payload: { 
        version: "1.0", 
        topics: [{ path: TOPIC_INVENTORY, type: "state", value: { last_updated: Date.now(), stock_items: inventory } }] 
    }
};

return [msgDecision, msgInv, { payload: "Decision Executed: " + action.action + " for " + action.batch_id }];

// TOPICS
const TOPIC_SHIPMENTS = "Henkelv2/Shanghai/Logistics/Outbound/State/Shipment_List";
const TOPIC_INVENTORY = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Inventory_Level";

let request = msg.payload;
// Expected: { customer, items: [{ sku, qty }] }

// 1. Get DBs
let shipmentDB = global.get('outbound_shipment_db') || { items: [] };
let inventory = global.get('internal_stock_list') || [];

// 2. Generate Delivery Note (DN) ID
let dnId = "DN-" + Math.floor(Math.random() * 100000);

// 3. Simple Allocation Logic (Find & Lock FG)
let allocatedItems = [];
let status = "CREATED";

request.items.forEach(reqItem => {
    // Find Available Finished Goods
    let stock = inventory.find(i => 
        i.sku === reqItem.sku && 
        (i.status === "AVAILABLE" || i.status === "RELEASED")
    );

    if (stock) {
        // Lock the stock
        stock.status = "ALLOCATED_OUTBOUND";
        stock.allocated_to_dn = dnId;
        allocatedItems.push({
            sku: reqItem.sku,
            batch: stock.batch_id,
            qty: stock.qty, // Assuming full pallet for demo
            hu: stock.hu
        });
    } else {
        status = "BACKORDERED"; // Stock not found
    }
});

// 4. Create Shipment Record
let newShipment = {
    dn_id: dnId,
    customer: request.customer,
    destination: request.destination || "3PL Central Hub",
    items: allocatedItems,
    status: status === "BACKORDERED" ? "HOLD" : "READY_TO_PICK",
    created_at: Date.now()
};

shipmentDB.items.unshift(newShipment);

// 5. Save Globals
global.set('outbound_shipment_db', shipmentDB);
global.set('internal_stock_list', inventory);

// 6. Publish Updates
let msgShip = {
    topic: TOPIC_SHIPMENTS,
    payload: { version: "1.0", topics: [{ path: TOPIC_SHIPMENTS, type: "state", value: shipmentDB }] }
};

let msgInv = {
    topic: TOPIC_INVENTORY,
    payload: { 
        version: "1.0", 
        topics: [{ path: TOPIC_INVENTORY, type: "state", value: { last_updated: Date.now(), stock_items: inventory } }] 
    }
};

return [msgShip, msgInv, { payload: newShipment }];

// TOPICS
const TOPIC_SHIPMENTS = "Henkelv2/Shanghai/Logistics/Outbound/State/Shipment_List";

let action = msg.payload;
// Expected: { dn_id, operator ... }

// 1. Get DB
let shipmentDB = global.get('outbound_shipment_db') || { items: [] };

// 2. Find Shipment
let shipIndex = shipmentDB.items.findIndex(s => s.dn_id === action.dn_id);
if (shipIndex !== -1) {
    // 3. Update Status
    shipmentDB.items[shipIndex].status = "PICKED"; // Ready for Packing
    shipmentDB.items[shipIndex].picked_at = Date.now();
    shipmentDB.items[shipIndex].picked_by = action.operator;

    // (Optional: In a real system, we would also update inventory location to 'PACK-STATION')
}

// 4. Save & Publish
global.set('outbound_shipment_db', shipmentDB);

msg.topic = TOPIC_SHIPMENTS;
msg.payload = { version: "1.0", topics: [{ path: TOPIC_SHIPMENTS, type: "state", value: shipmentDB }] };

return [msg, { payload: "Picked: " + action.dn_id }];

// TOPICS
const TOPIC_SHIPMENTS = "Henkelv2/Shanghai/Logistics/Outbound/State/Shipment_List";

let action = msg.payload;

// 1. Get DB
let shipmentDB = global.get('outbound_shipment_db') || { items: [] };

// 2. Find Shipment
let shipIndex = shipmentDB.items.findIndex(s => s.dn_id === action.dn_id);
if (shipIndex !== -1) {
    // 3. Update Status
    shipmentDB.items[shipIndex].status = "PACKED"; // Ready for Shipping
    shipmentDB.items[shipIndex].packed_at = Date.now();
    shipmentDB.items[shipIndex].tracking_no = "SF" + Math.floor(Math.random() * 10000000); // Simulate Label
}

// 4. Save & Publish
global.set('outbound_shipment_db', shipmentDB);

msg.topic = TOPIC_SHIPMENTS;
msg.payload = { version: "1.0", topics: [{ path: TOPIC_SHIPMENTS, type: "state", value: shipmentDB }] };

return [msg, { payload: "Packed: " + action.dn_id }];

// TOPICS
const TOPIC_SHIPMENTS = "Henkelv2/Shanghai/Logistics/Outbound/State/Shipment_List";
const TOPIC_INVENTORY = "Henkelv2/Shanghai/Logistics/Internal/Ops/State/Inventory_Level";

let action = msg.payload;
// Expected: { dn_id, carrier_info ... }

// 1. Get DBs
let shipmentDB = global.get('outbound_shipment_db') || { items: [] };
let inventory = global.get('internal_stock_list') || [];

// 2. Find Shipment
let shipIndex = shipmentDB.items.findIndex(s => s.dn_id === action.dn_id);
if (shipIndex !== -1) {
    let shipment = shipmentDB.items[shipIndex];

    // 3. Update Shipment Status
    shipment.status = "SHIPPED";
    shipment.shipped_at = Date.now();
