const COST_INTERNAL_PICK = 12.50;
const COST_3PL_INBOUND = 18.00;

let cost = 0;
let typeCheck = latestRecord.doc_type || latestRecord.type || "";

if (typeCheck.includes('INBOUND')) cost = COST_3PL_INBOUND;
if (typeCheck.includes('OUTBOUND')) cost = COST_INTERNAL_PICK;

let now = new Date();
let dayKey = now.toISOString().split('T')[0];
let monthKey = dayKey.substring(0, 7);

if (!financeDB.daily[dayKey]) financeDB.daily[dayKey] = { date: dayKey, Internal: 0, External: 0 };
if (!financeDB.monthly[monthKey]) financeDB.monthly[monthKey] = { month: monthKey, Internal: 0, External: 0 };

if (typeCheck.includes('INBOUND')) {
    financeDB.daily[dayKey].External += cost;
    financeDB.monthly[monthKey].External += cost;
} else {
    financeDB.daily[dayKey].Internal += cost;
    financeDB.monthly[monthKey].Internal += cost;
}

flow.set('last_processed_cost_id', currentId);
global.set('finance_history_v2', financeDB);

