let monthlyArray = Object.values(financeDB.monthly).sort((a, b) => a.month.localeCompare(b.month));

if (dailyArray.length < 2) {
    let today = new Date();
    for (let i = 5; i > 0; i--) {
        let d = new Date();
        d.setDate(today.getDate() - i);
        let dateStr = d.toISOString().split('T')[0];
