    { sku: "SEALANT-X", desc: "Premium Sealant Compound", warehouse: "DHL Shanghai Hub", type: "EXT", qty: 450, status: "AVAILABLE" }
];

let mergedStock = [...dynamicStock, ...baselineStock];

msg.payload = {
    "version": "1.0",
    "topics": [
        {
            "path": TOPIC_PATH,
            "type": "state",
            "value": {
                "last_updated": Math.floor(Date.now() / 1000),
                "stock_items": mergedStock
            }
        }
    ]
};

msg.topic = TOPIC_PATH;
return msg;

let newRates = msg.payload;
global.set('rate_card_db', newRates);
msg.payload = {
    version: "1.0",
    topics: [{
        path: "Henkelv2/Shanghai/Logistics/MasterData/State/Rate_Cards",
        value: newRates
    }]
};
msg.topic = "Henkelv2/Shanghai/Logistics/MasterData/State/Rate_Cards";
return msg;

const TOPIC_BILLING = "Henkelv2/Shanghai/Logistics/Finance/State/Monthly_Billing";

let allDNs = global.get('dn_db') || {};
let dnList = Object.values(allDNs);

let ourTotal = dnList.reduce((sum, dn) => sum + (dn.total_cost || 0), 0);
let dhlTotal = ourTotal + (Math.random() > 0.5 ? 500 : 0);
let diff = dhlTotal - ourTotal;

let invoice = {
    month: "2025-12",
    status: diff === 0 ? "MATCHED" : "DISCREPANCY",
    our_calculation: ourTotal,
    dhl_invoice_amount: dhlTotal,
    difference: diff,
    disputes: []
};

if (diff !== 0 && dnList.length > 0) {
    let randomDN = dnList[0];
    invoice.disputes.push({
        dn_no: randomDN.dn_no,
        reason: "Volume Mismatch",
        our_cost: randomDN.total_cost,
        dhl_cost: randomDN.total_cost + diff
    });
}

msg.payload = {
    version: "1.0",
    topics: [{ path: TOPIC_BILLING, type: "state", value: invoice }]
};
msg.topic = TOPIC_BILLING;
return msg;

let newDispute = msg.payload;
let disputeDB = global.get('dispute_db') || [];

disputeDB.unshift({
    id: newDispute.exception_id,
    reference: newDispute.sku || newDispute.dn_no || "Unknown",
    tpl_provider: "DHL",
    type: newDispute.reason_code,
    severity: newDispute.priority,
    status: "OPEN",
    created_date: new Date().toISOString(),
    notes: newDispute.notes
});

global.set('dispute_db', disputeDB);

msg.payload = {
    version: "1.0",
    topics: [{
        path: "Henkelv2/Shanghai/Logistics/Exceptions/State/Dispute_List",
        type: "state",
        value: disputeDB
    }]
};
msg.topic = "Henkelv2/Shanghai/Logistics/Exceptions/State/Dispute_List";
return msg;

let req = msg.payload;
let rates = global.get('rate_card_db') || {
    "basic": { "inbound": 2.0, "outbound": 3.0, "storage": 0.5 },
    "vas": { "activity_1": 2, "activity_2": 5, "activity_3": 15 }
};

let result = {};

if (req.type === "INTERNAL_ALLOCATION") {
    let total_opex = req.monthly_opex || 150000;
    let total_orders = 3500;
    result = {
        type: "INTERNAL",
        cost_per_unit: (total_opex / total_orders).toFixed(2),
        total_orders: total_orders
    };
} else {
    let allDNs = global.get('dn_db') || {};
    let dnList = Object.values(allDNs);

    let totalCost = dnList.reduce((sum, dn) => sum + (dn.total_cost || 0), 0);
    let inboundCount = dnList.filter(d => d.doc_type === 'INBOUND').length;
    let storageDays = dnList.reduce((sum, d) => sum + (d.breakdown?.storage_days || 0), 0);

    result = {
        type: "EXTERNAL",
        total_cost: totalCost,
        official_invoice_total: totalCost + (Math.random() > 0.8 ? 500 : 0),
        rate_card: {
            storage_per_day: rates.basic.storage,
            inbound_per_pallet: rates.basic.inbound,
            outbound_per_pallet: rates.basic.outbound,
            vas_per_item: rates.vas.activity_1
        },
        activity_summary: {
            inbound_pallets: inboundCount * 100,
            storage_days: storageDays * 100,
            vas_items: 50
        },
        breakdown: [
            { activity: "Inbound Handling", qty: inboundCount * 100, unit: "units", rate: rates.basic.inbound, total: inboundCount * 100 * rates.basic.inbound }
        ]
    };
}

msg.payload = {
    version: "1.0",
    topics: [{
        path: "Henkelv2/Shanghai/Logistics/Costing/State/Bill_Generated",
        type: "state",
        value: result
    }]
};
msg.topic = "Henkelv2/Shanghai/Logistics/Costing/State/Bill_Generated";
return msg;
